var e=[{id:`L3_1`,type:`dialog`,speaker:`MINATO_NANA_NULL_NULL`,text:{KOREA:`헉…… 허억……`,JPN:`はぁ……はぁ……`,ENG:`*Pant*`,TWN:`呼……呼呼……`},stage:{bg:`REEDS_FIELD_02`,slots:{L:null,C:{char_id:`MINATO_NANA_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`MINATO_NANA_NULL_NULL`,text:{KOREA:`이제 곧 산의 정상이야.`,JPN:`もうすぐ山の頂上だ。`,ENG:`I’m almost at the top of the mountain.`,TWN:`就快到山頂了。`},stage:{bg:`REEDS_FIELD_02`,slots:{L:null,C:{char_id:`MINATO_NANA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`MINATO_NANA_NULL_NULL`,text:{KOREA:`치나츠…… 제발.`,JPN:`千夏……どうか。`,ENG:`Chinatsu... Please...`,TWN:`千夏……拜託你…`},stage:{bg:`REEDS_FIELD_02`,slots:{L:null,C:{char_id:`MINATO_NANA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`MINATO_NANA_NULL_NULL`,text:{KOREA:`기다려…… 줘.`,JPN:`待っていて……くれ。`,ENG:`Wait for me...`,TWN:`一定要……等我。`},stage:{bg:`REEDS_FIELD_02`,slots:{L:null,C:{char_id:`MINATO_NANA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`MINATO_NANA_NULL_NULL`,text:{KOREA:`이건…… 뭐지?`,JPN:`これは……何だ？`,ENG:`What’s this?`,TWN:`怎麼……回事？`},stage:{bg:`SKY`,slots:{L:null,C:null,R:null}}},{id:`L11_1`,type:`dialog`,speaker:`MINATO_NANA_NULL_NULL`,text:{KOREA:`내가 여기서 뭘……`,JPN:`僕はここで何を……`,ENG:`Why am I here...`,TWN:`我怎麼會在這裡……`},stage:{bg:`SKY`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:null,text:{KOREA:`어이! 미나토!`,JPN:`おい！　湊！`,ENG:`Hey, Minato!`,TWN:`喂！南裕夏！`},stage:{bg:`SKY`,slots:{L:null,C:null,R:null}}},{id:`L13_1`,type:`dialog`,speaker:`MINATO_NANA_NULL_NULL`,text:{KOREA:`이 목소린……`,JPN:`この声は……`,ENG:`This voice...`,TWN:`這個聲音是……`},stage:{bg:`SKY`,slots:{L:null,C:null,R:null}}},{id:`L14_1`,type:`dialog`,speaker:`ZENZIROU_NANA_NULL_NULL`,text:{KOREA:`미나토! 지금 뭐하고 있는 거냐!`,JPN:`湊！　何やってんだよ！`,ENG:`Minato! What are you doing?`,TWN:`南裕夏！你到底在幹什麼？`},stage:{bg:`SKY`,slots:{L:null,C:{char_id:`ZENZIROU_NANA_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`MINATO_NANA_NULL_NULL`,text:{KOREA:`…….`,JPN:`……`,ENG:`...`,TWN:`……`},stage:{bg:`SKY`,slots:{L:null,C:{char_id:`ZENZIROU_NANA_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`ZENZIROU_NANA_NULL_NULL`,text:{KOREA:`나 참, 어디로 사라졌나 했더니 또 태평하게 낮잠이나 자고 있었구만.`,JPN:`どこに消えたかと思ったら、こんなところでまた昼寝でもしてたのか？`,ENG:`Hey, I was looking all over for you, and you were napping here?`,TWN:`真是的，我還以爲你跑去哪裡，結果又在這裡睡午覺！`},stage:{bg:`STREET_SPRING`,slots:{L:{char_id:`ZENZIROU_NANA_NULL_NULL`,face:`UNIT_LAUGH`},C:null,R:{char_id:`MINATO_NANA_NULL_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L20_1`,type:`dialog`,speaker:`MINATO_NANA_NULL_NULL`,text:{KOREA:`마사키? 네가 왜 여기에 있어? 하야미 씨는?`,JPN:`雅紀？　どうしてお前がここに？　速水さんは？`,ENG:`Masaki? What are you doing here? Where is Hayami?`,TWN:`雅紀？你為什麼在這裡？速水呢？`},stage:{bg:`STREET_SPRING`,slots:{L:{char_id:`ZENZIROU_NANA_NULL_NULL`,face:`UNIT_LAUGH`},C:null,R:{char_id:`MINATO_NANA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L21_1`,type:`dialog`,speaker:`ZENZIROU_NANA_NULL_NULL`,text:{KOREA:`잊었어? 오늘 궁도부 전국대회 출전날이잖아.`,JPN:`まさか忘れたのか？　今日は弓道部の全国大会の日だぞ。`,ENG:`Did you forget? Today is archery competition day!`,TWN:`你忘記啦？今天是參加弓道部全國比賽的日子。`},stage:{bg:`STREET_SPRING`,slots:{L:{char_id:`ZENZIROU_NANA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`MINATO_NANA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L22_1`,type:`dialog`,speaker:`ZENZIROU_NANA_NULL_NULL`,text:{KOREA:`1년 내내 준비했으면서 말이지.`,JPN:`1年間この日のために頑張ってただろ？`,ENG:`You’ve been practicing for a year.`,TWN:`辛辛苦苦準備了一整年！`},stage:{bg:`STREET_SPRING`,slots:{L:{char_id:`ZENZIROU_NANA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`MINATO_NANA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L23_1`,type:`dialog`,speaker:`MINATO_NANA_NULL_NULL`,text:{KOREA:`아…….`,JPN:`あ……`,ENG:`Oh...`,TWN:`喔……`},stage:{bg:`STREET_SPRING`,slots:{L:{char_id:`ZENZIROU_NANA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`MINATO_NANA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L24_1`,type:`dialog`,speaker:`MINATO_NANA_NULL_NULL`,text:{KOREA:`벌써 그렇게 됐던가?`,JPN:`もうそんな時期だっけ？`,ENG:`I didn’t know it’s been that long.`,TWN:`這麼快就到啦？`},stage:{bg:`STREET_SPRING`,slots:{L:{char_id:`ZENZIROU_NANA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`MINATO_NANA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L26_1`,type:`dialog`,speaker:`STUDENT_NPC_ARCHERY_GIRL`,text:{KOREA:`연습은 어때? 컨디션은 괜찮아?`,JPN:`練習はできた？　体の調子はどう？`,ENG:`Have you practiced enough? How are you feeling today?`,TWN:`訓練怎麼樣？狀態還好嗎？`},stage:{bg:`STREET_SPRING`,slots:{L:null,C:{char_id:`STUDENT_NPC_ARCHERY_GIRL`,face:`UNIT_IDLE`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`MINATO_NANA_NULL_NULL`,text:{KOREA:`…….`,JPN:`……`,ENG:`...`,TWN:`……`},stage:{bg:`STREET_SPRING`,slots:{L:null,C:{char_id:`MINATO_NANA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}}];export{e as default};